import React, { useMemo, useState, useEffect } from 'react';
import Select from 'react-select';

const EditPurchase = ({ purchase, handleUpdate, locations, materials, vendors }) => {
  
  
  const [editedPurchase, setEditedPurchase] = useState({ ...purchase });

  useEffect(() => {
    const editedvendorname = vendors.find((vendor) => vendor.name === purchase.vendor);
    const editedlocationname = locations.find((loc) => loc.locationname === purchase.location);
  
    setEditedPurchase((prevPurchase) => ({
      ...prevPurchase,
      vendorname: editedvendorname ? editedvendorname.vendorid : '',
      locationname: editedlocationname ? editedlocationname.id : '',
    }));
  }, [purchase, vendors, locations]);
  
  console.log('editedPurchase:', editedPurchase);

  const handleChange = (event) => {
    const { name, value } = event.target;
    setEditedPurchase((prevPurchase) => ({
      ...prevPurchase,
      [name]: value,
    }));
  };

  const handleSave = () => {
    handleUpdate(editedPurchase);

    // Check if vendor or price is changed to post to materialchangesAPI
    if (editedPurchase.vendor !== purchase.vendor || editedPurchase.price !== purchase.price) {
      const materialChangeData = {
        material_id: editedPurchase.materialid,
        vendor: editedPurchase.vendor,
        price: editedPurchase.price,
      };

      // Make a POST request to materialchangesAPI
      fetch('http://localhost:8081/materialchangesAPI', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(materialChangeData),
      })
        .then((response) => response.json())
        .then((data) => {
          console.log('Material changes saved:', data);
        })
        .catch((error) => {
          console.error('Error saving material changes:', error);
        });
    }
  };

  const vendorOptions = useMemo(
    () => vendors.map((vendor) => ({ value: vendor.vendorid, label: vendor.name })),
    [vendors]
  );

  const handleVendorChange = (selectedOption) => {
    if (!selectedOption) {
      setEditedPurchase((prevPurchase) => ({
        ...prevPurchase,
        vendor: '',
        vendorname: '',
      }));
      return;
    }
  
    const selectedVendor = vendors.find((vendor) => vendor.venorid === selectedOption?.label);
    setEditedPurchase((prevPurchase) => ({
      ...prevPurchase,
      vendor: selectedVendor ? selectedVendor.vendorid : '',
      vendorname: selectedOption ? selectedOption.label : '',
    }));
  };
  // Check if material.extras !== 1 to hide "Width" and "Lot No" inputs
  const hideWidthAndLotNo =
  materials.find((material) => material.matid === editedPurchase.materialid)?.extras !== 1;


  return (
    <div className="edit-purchase">
      <h2>Edit Purchase</h2>
      <div>
      <label>
        Location:
        <select name="location" value={editedPurchase.location} onChange={handleChange} required>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </label>
      </div>
      
      {hideWidthAndLotNo ? null : (
        <>
          <div>
            <label>
              Width:
              <input type="text" name="width" value={editedPurchase.width} onChange={handleChange} />
            </label>
          </div>
          <div>
            <label>
              Lot No:
              <input
                type="text"
                name="lotnumber"
                value={editedPurchase.lotnumber}
                onChange={handleChange}
              />
            </label>
          </div>
        </>
      )}
      <div>
        <label>
          Quantity:
          <input
            type="text"
            name="quantity"
            value={editedPurchase.quantity}
            onChange={handleChange}
          />
        </label>
      </div>
      <div>
        <label>
          Price:
          <input type="text" name="price" value={editedPurchase.price} onChange={handleChange} />
        </label>
      </div>
      <div>
      <label>Vendor:</label>
      <Select
        options={vendorOptions}
        value={
          editedPurchase.vendorname
            ? { value: editedPurchase.vendorname, label: editedPurchase.vendorname }
            : null
        }
        onChange={handleVendorChange}
        placeholder="Select a Vendor"
        isSearchable
        required
      />
      </div>
      <div>
        <button onClick={handleSave}>Save</button>
      </div>
    </div>
  );
};

export default EditPurchase;
